svg.script:

const interactive = document.querySelector('#interactive-layer');
const chips = document.querySelector('#chips');
const pulses = document.querySelector('#pulses');
const paths = document.querySelector('#paths');
const svg = document.querySelector('svg');
const svgNS = "http://www.w3.org/2000/svg";

let counter = 1;
addEventListener('click', (event) => {
    const allTargets = document.elementsFromPoint(event.clientX, event.clientY);
    const pathTargets = allTargets.filter(l => {
        return interactive.contains(l);
    })

    const chipTargets = allTargets.filter(l => {
        return chips.contains(l);
    })

    chipTargets.forEach(chip => {
        chipPulse(chip);
    });

    pathTargets.forEach(path => {
        animatePulse(path, event.clientX, event.clientY);
    });
});

let lastMove = 0;
addEventListener('mouseover', (event) => {
    const now = Date.now();
    if (now - lastMove < 100) return;
    const allTargets = document.elementsFromPoint(event.clientX, event.clientY);
    const filteredTargets = allTargets.filter(l => {
        return interactive.contains(l);
    })
    filteredTargets.forEach(path => {
        animatePulse(path, event.clientX, event.clientY);
    });
})

function chipPulse(chip){
    const chipId = chip.getAttribute('id');
    const chipPulses = document.querySelector(`#${chipId}-pulses`);
    const keyframes = [
    {strokeDashoffset: 60, offset: 0},
    {strokeDashoffset: -1000, offset: 0.4},
    {strokeDashoffset: -1000, offset: 1}
    ];
    if(chipPulses){
        const animation = chipPulses.animate(keyframes, {
            duration: 3000
        });
    }
    console.log(`${chipId}-pulses`);
}

function animatePulse(clickedPath, clickedX, clickedY){
    if (pulses.childElementCount > 20) return;
    let pt = svg.createSVGPoint();
    pt.x = clickedX;
    pt.y = clickedY;
    let svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    const pathId = clickedPath.id;
    const pathData = clickedPath.getAttribute('d');
    const pathDataArr = pathData.split(" ");

    let pathLength = clickedPath.getTotalLength();
    let pulseBegin = getLengthAtClick(clickedPath, svgP.x, svgP.y);

    const pulseWidth = 40;
    const newPulse = document.createElementNS(svgNS, "path");
    newPulse.setAttribute("d", pathData);
    newPulse.setAttribute("stroke", "#4e91fd8f");
    newPulse.setAttribute("filter", "url(#glow)");
    newPulse.setAttribute("stroke-width", "4");
    newPulse.setAttribute("stroke-linecap", "round");
    newPulse.setAttribute("fill", "none")
    newPulse.style.strokeDasharray = `${pulseWidth}, ${pathLength}`;

    pulses.appendChild(newPulse);

    let keyframes;
    let dist;
    if (pulseBegin/pathLength < 0.5){
        keyframes = [
            {strokeDashoffset: -pulseBegin, strokeOpacity: 0, offset: 0},
            {strokeOpacity: 0.3, offset: 0.05},
            {strokeDashoffset: -pathLength, strokeOpacity: 0.3, offset: 1}
        ];
        dist = (pathLength - pulseBegin)*1.5;
    }
    else{
        keyframes = [
            {strokeDashoffset: -pulseBegin+pulseWidth, strokeOpacity: 0, offset: 0},
            {strokeOpacity: 0.3, offset: 0.05,},
            {strokeDashoffset: pulseWidth, strokeOpacity: 0.3, offset: 1}
        ];
        dist = pulseBegin *1.5;
    }

    const animation = newPulse.animate(keyframes, {
        duration: dist
    });

    animation.onfinish = () => newPulse.remove();
    counter += 1;
}


function getLengthAtClick(path, x, y, precision = 2){
    const totalLength = path.getTotalLength();
    let bestDistance = 0;
    let minDiff = Infinity;

    for(let i = 0; i <= totalLength; i += precision){
        const point = path.getPointAtLength(i)

        const dx = x - point.x;
        const dy = y - point.y;
        const diffSq = dx * dx + dy * dy

        if (diffSq < minDiff){
            minDiff = diffSq;
            bestDistance = i;
        }
    }
    return bestDistance;
}
